 3→import { DndContext, type DragEndEvent, PointerSensor, useSensor, useSensors } from "@dnd-kit/core"
 4→import { KanbanColumn } from "./kanban-column"
 5→import type { DealData, DealStageData } from "@/lib/api/types"
 6→
 7→interface KanbanBoardProps {
 8→  deals: DealData[]
 9→  stages: DealStageData[]
10→  onMoveDeal: (dealId: string, toStageId: string) => void
11→}
12→
13→export function KanbanBoard({ deals, stages, onMoveDeal }: KanbanBoardProps) {
14→  const sensors = useSensors(
15→    useSensor(PointerSensor, {
16→      activationConstraint: {
17→        distance: 8,
18→      },
19→    })
20→  )
21→
22→  const handleDragEnd = (event: DragEndEvent) => {
23→    const { active, over } = event
24→
25→    if (!over) return
26→
27→    const dealId = active.id as string
28→    const toStageId = over.id as string
29→
30→    if (dealId && toStageId) {
31→      onMoveDeal(dealId, toStageId)
32→    }
33→  }
34→
35→  // Group deals by stage
36→  const dealsByStage = new Map<string, DealData[]>()
37→  stages.forEach((stage) => {
38→    dealsByStage.set(stage.id, [])
39→  })
40→
41→  deals.forEach((deal) => {
42→    if (dealsByStage.has(deal.stageId)) {
43→      dealsByStage.get(deal.stageId)!.push(deal)
44→    }
45→  })
46→
47→  return (
48→    <DndContext sensors={sensors} onDragEnd={handleDragEnd}>
49→      <div className="flex gap-4 overflow-x-auto pb-4">
50→        {stages.map((stage) => (
51→          <KanbanColumn
52→            key={stage.id}
53→            id={stage.id}
54→            title={stage.name}
55→            deals={dealsByStage.get(stage.id) || []}
56→            color={stage.color || undefined}
57→            probability={stage.probability}
58→            isWonStage={stage.isWonStage}
59→            isLostStage={stage.isLostStage}
60→          />
61→        ))}
62→      </div>
63→    </DndContext>
64→  )
65→}
